#include<bits/stdc++.h>
using namespace std;
long long a[2000010],b[2000010],t[2000010],p[2000010],n;
long long lowbit(long long x)
{
    return x&-x;
}
void update(long long x,long long v)
{
    for(long long i=x;i<=n*2;i+=lowbit(i))
    {
        t[i]+=v;
    }
}
long long query(long long x)
{
    long long ans=0;
    for(long long i=x;i>=1;i-=lowbit(i))
    {
        ans+=t[i];
    }
    return ans;
}
long long getsum(long long x,long long y)
{
    if(x>y)
    {
        y+=n;
    }
    if(y-x>=n)
    {
        y-=n;
    }
    return query(y)-query(x-1);
}
int main()
{
    long long x,y,z,l=1;
    scanf("%lld%lld%lld%lld",&n,&x,&y,&z);
    for(long long i=1;i<=n;i++)
    {
        scanf("%lld",&a[i]);
        p[a[i]]=i;
    }
    for(long long i=1;i<=n;i++)
    {
        scanf("%lld",&b[i]);
    }
    for(long long i=1;i<=n*2;i++)
    {
        update(i,1);
    }
    long long f1=z,f0=0;
    for(long long i=1;i<=n;i++)
    {
        long long w1=getsum(l,p[b[i]])-getsum(p[b[i]],p[b[i]]),w2=getsum(p[b[i]]+1,l+n);
        long long f00=f0,f11=f1;
        f0=min({f00+w1*x,f00+w2*y,f11+w1*x+z,f11+w2*y+z});
        f1=min({f00+w1*y+z,f00+w2*x+z,f11+w1*y,f11+w2*x});
        update(p[b[i]],-1);
        update(p[b[i]]+n,-1);
        l=p[b[i]];
    }
    printf("%lld",min(f0,f1));
    return 0;
}
